from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a monument (or related entity) into a single
    fluent sentence. All triples are combined; each predicate is expressed with a
    suitable phrase. Handles related entities (like country properties) using relative clauses.
    """
    if not triples:
        return ""

    # Group triples by subject
    triples_by_subject: dict[str, list[Triple]] = {}
    for triple in triples:
        if triple.subject not in triples_by_subject:
            triples_by_subject[triple.subject] = []
        triples_by_subject[triple.subject].append(triple)

    # Main subject is the monument (first triple's subject)
    subject = triples[0].subject
    main_triples = triples_by_subject.get(subject, [])
    other_subjects = [s for s in triples_by_subject.keys() if s != subject]

    clauses: list[str] = []

    # Process main subject predicates
    for triple in main_triples:
        p = triple.predicate
        o = triple.object.strip('"')  # remove surrounding quotes if present

        # Map predicates to natural-language fragments
        if p == "category":
            clauses.append(f"is a {o}")
        elif p == "country":
            clauses.append(f"is in {o}")
        elif p == "location":
            clauses.append(f"is located in {o}")
        elif p == "municipality":
            clauses.append(f"located in the municipality of {o}")
        elif p == "state":
            clauses.append(f"in the state of {o}")
        elif p == "district":
            clauses.append(f"part of the district {o}")
        elif p in ("established", "foundingDate"):
            clauses.append(f"was established on {o}")
        elif p in ("owner", "owningOrganisation"):
            clauses.append(f"owned by {o}")
        elif p == "inaugurationDate":
            clauses.append(f"was inaugurated on {o}")
        elif p == "capital":
            clauses.append(f"capital is {o}")
        elif p == "legislature":
            clauses.append(f"legislature is {o}")
        elif p == "dedicatedTo":
            clauses.append(f"dedicated to {o}")
        elif p == "designer":
            clauses.append(f"designed by {o}")
        elif p == "material":
            clauses.append(f"made of {o}")
        elif p == "ethnicGroup":
            clauses.append(f"with ethnic group {o}")
        elif p == "language":
            clauses.append(f"where the language is {o}")
        elif p == "religion":
            clauses.append(f"where the religion is {o}")
        elif p == "nearestCity":
            clauses.append(f"nearest city is {o}")
        elif p == "currency":
            clauses.append(f"uses currency {o}")
        elif p == "largestCity":
            clauses.append(f"largest city is {o}")
        elif p == "leader":
            clauses.append(f"leader is {o}")
        elif p == "leaderTitle":
            clauses.append(f"leader title is {o}")
        elif p.startswith("hasToIts"):
            direction = p.replace("hasToIts", "").lower()
            clauses.append(f"has to its {direction} {o}")
        elif p == "nativeName":
            clauses.append(f'native name is "{o}"')
        else:
            # Fallback for any unexpected predicate
            clauses.append(f"{p} {o}")

    # Build the main sentence
    if not clauses:
        return subject

    # Join clauses with proper connectors
    if len(clauses) == 1:
        main_sentence = f"{subject} {clauses[0]}."
    else:
        main_sentence = f"{subject} {', '.join(clauses[:-1])}, and {clauses[-1]}."

    # Add information about related entities (e.g., country properties) using relative clauses
    if other_subjects:
        for other_subject in other_subjects:
            other_triples = triples_by_subject[other_subject]
            other_clauses = []

            for triple in other_triples:
                p = triple.predicate
                o = triple.object.strip('"')

                if p == "capital":
                    other_clauses.append(f"capital is {o}")
                elif p == "largestCity":
                    other_clauses.append(f"largest city is {o}")
                elif p == "population":
                    other_clauses.append(f"population is {o}")
                elif p == "area":
                    other_clauses.append(f"area is {o}")
                else:
                    other_clauses.append(f"{p} {o}")

            if other_clauses:
                relative_clause = f" (which {', '.join(other_clauses[:-1])} and {other_clauses[-1]})" if len(other_clauses) > 1 else f" (which {other_clauses[0]})"
                main_sentence = main_sentence.rstrip('.') + relative_clause + "."

    return main_sentence

